from flask import Flask, request, jsonify
from flask_login import LoginManager, UserMixin, login_user, logout_user, current_user, login_required
from flask_mfa import MFA, mfa_prompt

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your-secret-key'

login_manager = LoginManager()
login_manager.init_app(app)

MFA(app)

class User(UserMixin):
    pass

users = {
    'alice': {'password': 'hashed_password', 'mfa_enabled': True},
    # ... other users
}

@login_manager.user_loader
def load_user(user_id):
    return next((user for user in users.values() if user['username'] == user_id), None)

@app.route('/api/login', methods=['POST'])
def login():
    user = load_user(request.form['username'])
    if not user or not user.check_password(request.form['password']):
        return jsonify({'error': 'Invalid credentials'}), 401

    if user.mfa_enabled:
        otp = request.form['otp']
        verified = mfa_prompt()(otp)
        if not verified:
            return jsonify({'error': 'Invalid OTP'}), 403

    login_user(user)
    return jsonify({'message': 'Logged in successfully'})

@app.route('/api/direct-login', methods=['POST'])
def direct_login():
    user = load_user(request.form['username'])
    if not user:
        return jsonify({'error': 'Invalid username'}), 401

    login_user(user)
    return jsonify({'message': 'Logged in directly'})

@app.route('/api/logout')
@login_required
def logout():
    logout_user()
    return jsonify({'message': 'Logged out successfully'})